import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class SecurePathTraversalExample {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd";

        String basePath = "/var/www/data/";

        // Sanitize and validate user input to prevent Path Traversal
        if (!userInput.contains("..") && !userInput.startsWith("/")) {
            String fullPath = basePath + userInput;

            try {
                File file = new File(fullPath);
                if (file.exists()) {
                    byte[] content = Files.readAllBytes(Paths.get(fullPath));
                    System.out.println(new String(content));
                } else {
                    System.out.println("File not found.");
                }
            } catch (IOException e) {
                System.err.println("Error reading file: " + e.getMessage());
            }
        } else {
            System.out.println("Invalid file path.");
        }
    }
}

